head.b:skin:
:root {
    --primary: #e74c3c;
    --primary-light: #ff6b5b;
    --primary-dark: #c0392b;
    --secondary: #0f172a;
    --secondary-light: #1e293b;
    --bg-light: #f0f4f8;
    --surface: #ffffff;
    --surface-glass: rgba(255, 255, 255, 0.95);
    --border: rgba(226, 232, 240, 0.6);
    --text-dark: #0f172a;
    --text-muted: #64748b;
    --gradient-primary: linear-gradient(135deg, #e74c3c 0%, #c0392b 100%);
    --gradient-dark: linear-gradient(135deg, #0f172a 0%, #1e293b 100%);
    --shadow-sm: 0 2px 8px rgba(0,0,0,0.04);
    --shadow-md: 0 8px 20px rgba(0,0,0,0.06);
    --shadow-lg: 0 20px 35px -10px rgba(0,0,0,0.1);
    --transition: all 0.35s cubic-bezier(0.4, 0, 0.2, 1);
    --border-radius-md: 20px;
    --border-radius-lg: 28px;
}

* { margin: 0; padding: 0; box-sizing: border-box; }

body {
    background: var(--bg-light);
    font-family: 'Inter', 'Hind Siliguri', sans-serif;
    color: var(--text-dark);
    padding-top: 70px;
    line-height: 1.5;
}

body::before {
    content: '';
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background-image: radial-gradient(circle at 25% 40%, rgba(231,76,60,0.03) 0%, transparent 50%);
    pointer-events: none;
    z-index: -1;
}

.container { max-width: 1280px; margin: 0 auto; padding: 0 28px; }

/* Header */
header {
    background: rgba(255,255,255,0.98);
    backdrop-filter: blur(10px);
    height: 70px;
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    z-index: 1000;
    border-bottom: 1px solid var(--border);
}

.header-flex {
    display: flex;
    align-items: center;
    justify-content: space-between;
    height: 70px;
}

.logo-area { display: flex; align-items: center; gap: 10px; }
.logo-icon { font-size: 28px; background: var(--gradient-primary); -webkit-background-clip: text; background-clip: text; color: transparent; }
.logo { font-size: 24px; font-weight: 800; text-decoration: none; background: linear-gradient(135deg, #0f172a 0%, #334155 100%); -webkit-background-clip: text; background-clip: text; color: transparent; }
.logo span { background: var(--gradient-primary); -webkit-background-clip: text; background-clip: text; color: transparent; }

/* Small Hero */
.hero {
    background: var(--gradient-dark);
    border-radius: var(--border-radius-lg);
    padding: 25px 35px;
    margin: 20px 0 35px;
    color: white;
    text-align: center;
    position: relative;
    overflow: hidden;
    box-shadow: var(--shadow-lg);
}
.hero::before { content: '📰'; position: absolute; font-size: 120px; opacity: 0.06; bottom: -20px; right: -15px; pointer-events: none; }
.hero-badge { display: inline-block; background: rgba(255,255,255,0.12); border-radius: 50px; padding: 4px 16px; font-size: 0.7rem; margin-bottom: 10px; }
.hero h1 { font-size: 1.6rem; font-weight: 800; margin-bottom: 6px; }
.hero p { font-size: 0.85rem; opacity: 0.85; }
.hero-stats { display: flex; justify-content: center; gap: 18px; margin-top: 14px; flex-wrap: wrap; }
.hero-stats div { background: rgba(255,255,255,0.08); padding: 4px 16px; border-radius: 40px; font-size: 0.7rem; }
.hero-stats i { margin-right: 5px; color: var(--primary-light); }

/* Layout */
.main-wrapper { display: flex; flex-wrap: wrap; gap: 32px; margin-bottom: 50px; }
.main-content { flex: 2.5; min-width: 0; }
.sidebar-right { flex: 1; min-width: 280px; }

/* Categories */
.category-section { margin-bottom: 45px; animation: fadeInUp 0.5s ease-out forwards; opacity: 0; }
@keyframes fadeInUp { from { opacity: 0; transform: translateY(15px); } to { opacity: 1; transform: translateY(0); } }
.category-section:nth-child(1) { animation-delay: 0.05s; }
.category-section:nth-child(2) { animation-delay: 0.1s; }
.category-section:nth-child(3) { animation-delay: 0.15s; }
.category-section:nth-child(4) { animation-delay: 0.2s; }
.category-section:nth-child(5) { animation-delay: 0.25s; }
.category-section:nth-child(6) { animation-delay: 0.3s; }

.cat-header { display: flex; align-items: center; gap: 12px; margin-bottom: 22px; padding-left: 16px; position: relative; }
.cat-header::before { content: ''; position: absolute; left: 0; top: 0; bottom: 0; width: 4px; background: var(--gradient-primary); border-radius: 10px; }
.cat-header i { font-size: 1.4rem; background: var(--gradient-primary); -webkit-background-clip: text; background-clip: text; color: transparent; }
.cat-header h2 { font-size: 1.5rem; font-weight: 700; color: var(--secondary); }

/* Cards */
.news-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(180px, 1fr)); gap: 20px; }
.news-card {
    background: var(--surface);
    border-radius: var(--border-radius-md);
    padding: 20px 14px 18px;
    text-align: center;
    border: 1px solid var(--border);
    transition: var(--transition);
    cursor: pointer;
    position: relative;
    overflow: hidden;
    box-shadow: var(--shadow-sm);
}
.news-card::before { content: ''; position: absolute; top: 0; left: -100%; width: 100%; height: 3px; background: var(--gradient-primary); transition: var(--transition); }
.news-card:hover::before { left: 0; }
.news-card:hover { transform: translateY(-5px); border-color: transparent; box-shadow: var(--shadow-lg); }
.news-card img { width: 52px; height: 52px; border-radius: 16px; margin-bottom: 12px; background: #fff; padding: 5px; object-fit: contain; transition: var(--transition); }
.news-card:hover img { transform: scale(1.05); }
.news-card span { display: block; font-weight: 700; font-size: 0.88rem; color: var(--text-dark); }
.news-card small { font-size: 0.65rem; color: var(--text-muted); margin-top: 6px; display: block; }

/* Sidebar */
.sidebar-widget {
    background: var(--surface-glass);
    backdrop-filter: blur(10px);
    border-radius: var(--border-radius-lg);
    border: 1px solid var(--border);
    padding: 22px;
    margin-bottom: 28px;
    box-shadow: var(--shadow-md);
}
.sidebar-widget:hover { transform: translateY(-3px); box-shadow: var(--shadow-lg); }
.sidebar-widget-title { font-size: 1.2rem; font-weight: 700; background: var(--gradient-primary); -webkit-background-clip: text; background-clip: text; color: transparent; display: inline-block; padding-bottom: 6px; margin-bottom: 18px; border-bottom: 2px solid var(--primary-light); }
.sidebar-list { list-style: none; }
.sidebar-list li { margin-bottom: 12px; padding: 6px 0 6px 12px; border-left: 3px solid var(--border); transition: var(--transition); }
.sidebar-list li:hover { border-left-color: var(--primary); background: rgba(231,76,60,0.05); border-radius: 0 10px 10px 0; }
.sidebar-list a { text-decoration: none; color: var(--text-dark); font-weight: 500; display: flex; align-items: center; gap: 10px; cursor: pointer; font-size: 0.88rem; }
.sidebar-list a:hover { color: var(--primary); transform: translateX(4px); }
.sidebar-list i { width: 26px; color: var(--primary); }

/* Modal - Simple, No Auto Error Detection */
.modal-view {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0,0,0,0.96);
    backdrop-filter: blur(12px);
    z-index: 9999;
    display: none;
    flex-direction: column;
    animation: fadeIn 0.3s ease;
}
@keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }

.modal-bar {
    background: var(--secondary-light);
    padding: 14px 24px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-wrap: wrap;
    gap: 12px;
}
.modal-bar .site-info { display: flex; align-items: center; gap: 14px; flex-wrap: wrap; }

.action-buttons { display: flex; gap: 10px; flex-wrap: wrap; }
.action-btn {
    background: rgba(255,255,255,0.1);
    border: 1px solid rgba(255,255,255,0.2);
    color: #fff;
    padding: 6px 16px;
    border-radius: 40px;
    cursor: pointer;
    font-size: 0.8rem;
    transition: var(--transition);
    text-decoration: none;
    display: inline-flex;
    align-items: center;
    gap: 6px;
}
.action-btn:hover { background: var(--primary); border-color: var(--primary); transform: scale(1.02); }
.bypass-btn { background: #2c7da0; border-color: #2c7da0; }
.bypass-btn:hover { background: #1f5e7a; }

iframe#readerFrame { flex: 1; border: none; background: #fff; width: 100%; }
.close-btn { background: var(--gradient-primary); border: none; color: #fff; padding: 6px 20px; border-radius: 40px; cursor: pointer; font-weight: 600; }

/* Manual Error Message - Only shown when user clicks "Show Error" or iframe fails visibly */
.error-message {
    display: none;
    text-align: center;
    padding: 60px 30px;
    background: var(--surface);
    height: 100%;
    flex-direction: column;
    align-items: center;
    justify-content: center;
}
.error-icon { font-size: 70px; margin-bottom: 20px; }
.error-message h3 { font-size: 1.6rem; margin-bottom: 10px; color: var(--secondary); }
.error-message p { margin-bottom: 15px; color: var(--text-muted); max-width: 500px; }
.error-solutions {
    background: #f8f9fa;
    border-radius: 16px;
    padding: 20px;
    margin: 20px 0;
    text-align: left;
    max-width: 500px;
}
.error-solutions h4 { color: var(--primary); margin-bottom: 12px; font-size: 1rem; }
.error-solutions ul { list-style: none; }
.error-solutions li { margin: 10px 0; display: flex; align-items: center; gap: 10px; }
.error-solutions i { width: 24px; color: var(--primary); }
.bypass-buttons { display: flex; gap: 12px; flex-wrap: wrap; justify-content: center; margin-top: 15px; }
.bypass-option {
    background: var(--gradient-primary);
    color: white;
    padding: 10px 24px;
    border-radius: 50px;
    text-decoration: none;
    font-weight: 600;
    font-size: 0.9rem;
    transition: var(--transition);
    display: inline-flex;
    align-items: center;
    gap: 8px;
}
.bypass-option:hover { transform: scale(1.05); filter: brightness(1.05); }
.proxy-option { background: #2c7da0; }

/* Footer */
footer {
    background: var(--gradient-dark);
    color: #cbd5e1;
    padding: 40px 0 20px;
    margin-top: 40px;
    border-radius: var(--border-radius-lg) var(--border-radius-lg) 0 0;
}
.footer-grid { display: flex; flex-wrap: wrap; gap: 40px; justify-content: space-between; margin-bottom: 35px; }
.footer-col { flex: 1; min-width: 170px; }
.footer-logo { font-size: 22px; font-weight: 800; color: white; margin-bottom: 12px; display: inline-block; }
.footer-logo span { color: var(--primary-light); }
.footer-text { opacity: 0.7; font-size: 0.8rem; }
.footer-title { color: white; font-weight: 700; margin-bottom: 16px; border-left: 3px solid var(--primary); padding-left: 12px; font-size: 1rem; }
.footer-links { list-style: none; }
.footer-links li { margin-bottom: 10px; }
.footer-links a { color: #cbd5e1; text-decoration: none; transition: var(--transition); font-size: 0.85rem; }
.footer-links a:hover { color: var(--primary-light); padding-left: 5px; }
.copyright { text-align: center; padding-top: 20px; border-top: 1px solid rgba(255,255,255,0.08); font-size: 0.75rem; }

@media (max-width: 800px) {
    body { padding-top: 60px; }
    .hero h1 { font-size: 1.3rem; }
    .hero { padding: 18px 20px; margin: 15px 0 25px; }
    .main-wrapper { flex-direction: column; }
    .news-grid { grid-template-columns: repeat(auto-fill, minmax(150px, 1fr)); gap: 14px; }
    .cat-header h2 { font-size: 1.3rem; }
    header { height: auto; }
    body { padding-top: 90px; }
    .header-flex { height: auto; padding: 10px 0; flex-direction: column; }
}
@media (max-width: 480px) {
    .container { padding: 0 16px; }
    .news-grid { grid-template-columns: repeat(2, 1fr); gap: 12px; }
}

body.script:
//
    var currentUrl = '';
    var currentName = '';

    function viewNews(url, name) {
        if (!url) return;
        currentUrl = url;
        currentName = name || 'পত্রিকা';

        var modal = document.getElementById('newsModal');
        var frame = document.getElementById('readerFrame');
        var errorDiv = document.getElementById('iframeError');
        var titleSpan = document.getElementById('activePaper');
        var newTabLink = document.getElementById('openInNewTab');
        var errorLink = document.getElementById('errorOpenLink');
        var errorSiteName = document.getElementById('errorSiteName');

        if (titleSpan) titleSpan.innerHTML = '<i class="fas fa-globe"></i> ' + currentName;
        if (newTabLink) newTabLink.href = url;
        if (errorLink) errorLink.href = url;
        if (errorSiteName) errorSiteName.innerText = currentName;

        // Hide error and load iframe
        if (errorDiv) errorDiv.style.display = 'none';
        if (frame) {
            frame.style.display = 'block';
            frame.src = url;
        }

        if (modal) modal.style.display = 'flex';
        document.body.style.overflow = 'hidden';
    }

    // Manual error button - user clicks this if site doesn't load
    function showManualError() {
        var frame = document.getElementById('readerFrame');
        var errorDiv = document.getElementById('iframeError');

        if (frame && errorDiv) {
            frame.style.display = 'none';
            errorDiv.style.display = 'flex';
        }
    }

    function closeNews() {
        var modal = document.getElementById('newsModal');
        var frame = document.getElementById('readerFrame');
        var errorDiv = document.getElementById('iframeError');

        if (modal) modal.style.display = 'none';
        if (frame) {
            frame.src = '';
            frame.style.display = 'block';
        }
        if (errorDiv) errorDiv.style.display = 'none';
        document.body.style.overflow = 'auto';
    }

    // ESC key to close
    document.addEventListener('keydown', function(e) {
        if (e.key === 'Escape') {
            var modal = document.getElementById('newsModal');
            if (modal && modal.style.display === 'flex') closeNews();
        }
    });

    // Click background to close
    var modal = document.getElementById('newsModal');
    if (modal) {
        modal.addEventListener('click', function(e) {
            if (e.target === modal) closeNews();
        });
    }
//
